  ('investigation-b89e2ba5-moex-00022', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '雇主與勞工為離職後競業禁止之約定時，關於約定之期間，下列敘述何者正確？', '["最長不得逾5年，逾5年者，其約定無效", "最長不得逾4年，逾4年者，其約定無效", "最長不得逾3年，逾3年者，縮短為3年", "最長不得逾2年，逾2年者，縮短為2年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00023', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '關於憲法修改後政府體制變化的說明，下列何者正確？', '["為強化對大法官審判獨立的保障，將大法官的任期由8年改為終身職", "廢除國民大會，由立法院行使提出罷免總統副總統以及修憲案的權限", "廢除總統對行政院院長的人事提名權，改由立法院行使此一人事提名權", "修憲後如提出覆議案，當立法院仍維持原決議，行政院院長應辭職負責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00024', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '中央法規標準法第13條規定，法規明定自公布或發布日施行者，自公布或發布之日起算至第三日起 發生效力。依據司法院釋字第161號解釋意旨，法規公布或發布之當日應否計入起算日？', '["法規公布或發布之當日應計入起算日", "起算日之認定屬立法院職權，應由立法院決定", "起算日之認定屬總統職權，應由總統決定", "法規公布或發布之當日不應計入起算日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00025', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '刑事訴訟法第163條第2項但書所指法院應依職權調查之「公平正義之維護」事項，應以利益被告之 事項為限，否則即與檢察官應負實質舉證責任之規定及無罪推定原則相牴觸，無異回復糾問制度，而 悖離整體法律秩序理念。就此而言，主要是採取下列何種解釋方法？', '["文義解釋", "目的性限縮解釋", "目的性擴張解釋", "歷史解釋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00026', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '甲向A公司租用C轎車半年，並僱用乙為員工兼司機，上班時間或有必要時，將C車交由乙駕駛及 保管。下列敘述何者正確？', '["在租用期間，A公司非C車的占有人", "上班時間，乙為C車的直接占有人", "在租用期間，甲為C車的直接占有人", "上班期間，甲為C車的間接占有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00027', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '下列那一種臺灣地區人民在中國持有的證件，根據大陸委員會114年4月16日的解釋函令規定，依 據臺灣地區與大陸地區人民關係條例第9條之1，喪失臺灣地區人民身分及其在臺灣地區選舉、罷免、 創制、複決、擔任軍職、公職及其他以在臺灣地區設有戶籍所衍生相關權利，並由戶政機關註銷其臺 灣地區之戶籍登記？', '["居住證", "定居證", "就業證", "台胞證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00028', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '下列那一項不是2006年中國通過的反分裂法第8條所規定國家得採取非和平方式及其他必要措施， 捍衛國家主權和領土完整？', '["臺獨分裂勢力以任何名義、任何方式造成臺灣從中國分裂出去的事實", "發生將會導致臺灣從中國分裂出去的重大事變", "臺灣舉行統一公投", "和平統一的可能性完全喪失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00029', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '中國《海警法》第三章規定海警可對外國船隻進行登檢或驅離。根據《聯合國海洋法公約》（UNCLOS） 第17條至第19條對「無害通過權」的規範，下列那一項說法最為正確？', '["《海警法》完全符合聯合國海洋法公約，因為沿海國有權在領海內驅逐任何船隻，不論是否無害", "《海警法》可能違反聯合國海洋法公約，因其賦予海警過度的執法裁量，限制了外國船隻在不危害 沿海國安全前提下的無害通過權", "聯合國海洋法公約並未規範「無害通過」，所以中國可依國內法自由處理進入領海的外國船隻", "中國是聯合國海洋法公約締約國，其國內法自動優先於國際法，因此無違反問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00030', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '根據臺灣地區與大陸地區人民關係條例第5條之3，有關涉及政治議題之協議，下列那一項為正確？', '["行政院得逕行開啟協商，事後報請立法院備查", "行政院應於協商開始90日內，將協議計畫送交立法院審查", "行政院應於協商開始90日前，提出協議締結計畫及影響評估報告，並經立法院四分之一立法委員 同意後，始得協商", "行政院應於協商開始90日前，提出協議締結計畫及評估報告，並經全體立法委員四分之三出席， 及出席委員四分之三同意，始得開啟協商"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL),
  ('investigation-b89e2ba5-moex-00031', 'investigation-b89e2ba5', 'investigation-b89e2ba5-moex-114-44c4f898', 'sub-investigation-b89e2ba5-02', NULL, 'single_choice', '根據臺灣地區與大陸地區人民關係條例第18條之規定，對於有「危害國家安全或社會安定之虞」之 大陸地區人民，內政部移民署得採取何種措施？', '["暫時限制其停留或居留資格，並進行相關調查", "內政部移民署得逕行強制出境，或限令其於十日內出境，逾限令出境期限仍未出境，內政部移民署 得強制出境", "內政部移民署只得限令其於十日內出境，逾限令出境期限仍未出境，內政部移民署得強制出境", "內政部移民署只能約談和告誡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:40+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "415", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "資訊科學組"}'::jsonb, NULL)
